comment_data.body:
This is possible with something like the following patch. But on reflection, it's probably not worth it since scanning string params is probably not a bottleneck.

```diff
diff --git a/src/nvim/eval.lua b/src/nvim/eval.lua
index 1704f4d9a28b..4dd424b48e86 100644
--- a/src/nvim/eval.lua
+++ b/src/nvim/eval.lua
@@ -7,6 +7,7 @@
 --- @field func? string (default: "f_{funcname}") C function which implements the vimfn.
 --- @field func_float? string Floating-point C function. Sets func="float_op_wrapper".
 --- @field func_lua? string Function name in `vim._core.vimfn.*` (e.g. "f_hostname"). Sets func="lua_wrapper".
+--- @field args_blob? integer[] Args (1-indexed) whose Lua strings convert to VAR_BLOB (skips NUL scan).
 --- @field fast? boolean Function can run in |api-fast| events. Defaults to false.
 --- @field deprecated? true
 --- @field returns? string|false
@@ -13657,6 +13658,7 @@ M.funcs = {
   },
   writefile = {
     args = { 2, 3 },
+    args_blob = { 1 },
     base = 1,
     desc = [=[
       When {object} is a |List| write it to file {fname}.  Each list
diff --git a/src/nvim/eval/funcs.h b/src/nvim/eval/funcs.h
index 54b74d9cc91e..b3d6b03c3fd8 100644
--- a/src/nvim/eval/funcs.h
+++ b/src/nvim/eval/funcs.h
@@ -23,6 +23,7 @@ typedef struct {
   uint8_t min_argc;   ///< Minimal number of arguments.
   uint8_t max_argc;   ///< Maximal number of arguments.
   uint8_t base_arg;   ///< Method base arg # (1-indexed), BASE_NONE or BASE_LAST.
+  uint8_t args_blob;  ///< Bitmask: args (1-indexed) whose Lua strings convert to VAR_BLOB.
   bool fast;          ///< Can be run in |api-fast| events
   VimLFunc func;      ///< Function implementation.
   EvalFuncData data;  ///< Userdata for function implementation.
diff --git a/src/nvim/lua/executor.c b/src/nvim/lua/executor.c
index 02a95d5f6d49..9f78abea84cd 100644
--- a/src/nvim/lua/executor.c
+++ b/src/nvim/lua/executor.c
@@ -1344,11 +1344,24 @@ int nlua_call(lua_State *lstate)
     return 1;
   }

+  const EvalFuncDef *fdef = find_internal_func(name);
+
   typval_T vim_args[MAX_FUNC_ARGS + 1];
   int i = 0;  // also used for freeing the variables
   for (; i < nargs; i++) {
     lua_pushvalue(lstate, i + 2);
-    if (!nlua_pop_typval(lstate, &vim_args[i])) {
+    // For args marked with args_blob, convert Lua strings directly to VAR_BLOB.
+    // Skips the memchr() NUL-scan that decode_string() normally does.
+    if (fdef && (fdef->args_blob & (1 << i)) && lua_type(lstate, -1) == LUA_TSTRING) {
+      size_t len;
+      const char *s = lua_tolstring(lstate, -1, &len);
+      blob_T *b = tv_blob_alloc();
+      ga_concat_len(&b->bv_ga, s, len);
+      vim_args[i].v_type = VAR_BLOB;
+      vim_args[i].v_lock = VAR_UNLOCKED;
+      vim_args[i].vval.v_blob = b;
+      lua_pop(lstate, 1);
+    } else if (!nlua_pop_typval(lstate, &vim_args[i])) {
       api_set_error(&err, kErrorTypeException,
                     "error converting argument %d", i + 1);
       goto free_vim_args;
